<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/stripe_finalizacion.php';exigirRol(['usuario']);
$sessionId=substr(trim((string)($_GET['session_id']??'')),0,255);$resultado=null;
try{$resultado=finalizarCompraStripe($sessionId,(int)$_SESSION['usuario_id']);}catch(Throwable$e){error_log('Retorno Stripe capacitación: '.preg_replace('/[\r\n\t]+/',' ',$e->getMessage()));}
$pago=null;if($resultado&&$resultado['tipo']==='capacitacion'){$q=obtenerConexion()->prepare("SELECT cp.id,cp.importe,cp.moneda,a.nombre,i.id inscripcion_id,i.estado estado_inscripcion,s.codigo FROM capacitacion_pagos cp JOIN asignaturas a ON a.id=cp.asignatura_id LEFT JOIN inscripciones_capacitacion i ON i.pago_id=cp.id LEFT JOIN capacitacion_secciones s ON s.id=i.seccion_id WHERE cp.id=:id AND cp.usuario_id=:u AND cp.estado='pagado' AND cp.es_intencion_checkout=0");$q->execute(['id'=>$resultado['pago_id'],'u'=>$_SESSION['usuario_id']]);$pago=$q->fetch();}
$pageTitle='Pago completado | Atenea';require dirname(__DIR__,2).'/includes/header.php';
?><main class="main"><section class="section"><div class="container" style="max-width:760px"><div class="card shadow-sm"><div class="card-body p-5 text-center"><?php if($pago):?><h1 class="h3">¡Pago completado!</h1><p>Tu capacitación <strong><?=atenea_e($pago['nombre'])?></strong> fue procesada correctamente.</p><p>Pago: <strong>Completado</strong><br>Inscripción: <strong>Activa</strong><?php if($pago['estado_inscripcion']==='pendiente_asignacion'):?> · sección por asignar<?php elseif($pago['codigo']):?> · sección <?=atenea_e($pago['codigo'])?><?php endif;?></p><div class="d-flex flex-wrap gap-2 justify-content-center"><a class="btn-atenea" href="<?=atenea_url('src/estudiantes/cursos.php')?>">Ir a mi capacitación</a><a class="btn btn-outline-secondary" href="<?=atenea_url('src/comprobantes/descargar-capacitacion.php?pago='.(int)$pago['id'].'&tipo=pdf')?>">Descargar PDF</a><a class="btn btn-outline-secondary" href="<?=atenea_url('src/comprobantes/descargar-capacitacion.php?pago='.(int)$pago['id'].'&tipo=json')?>">Descargar JSON</a></div><?php else:?><h1 class="h3">No pudimos sincronizar tu pago en este momento</h1><p>No vuelvas a pagar. Estamos verificando la operación de forma segura con Stripe.</p><a class="btn-atenea" href="?session_id=<?=rawurlencode($sessionId)?>">Volver a verificar</a><?php endif;?></div></div></div></section></main><?php require dirname(__DIR__,2).'/includes/footer.php';
